SELECT id, link_id, source_id, title, url, school, field, journals, publish_time,
       tech_keywords, stage, domain, application_scenario, created_at
FROM achievement


        AND school LIKE CONCAT('%', #{school}, '%')


        AND domain = #{domain}


        AND stage = #{stage}


        AND (title LIKE CONCAT('%', #{keyword}, '%')
             OR tech_keywords LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY id DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM achievement


        AND school LIKE CONCAT('%', #{school}, '%')


        AND domain = #{domain}


        AND stage = #{stage}


        AND (title LIKE CONCAT('%', #{keyword}, '%')
             OR tech_keywords LIKE CONCAT('%', #{keyword}, '%'))
